import Button from "../../components/Login/Button";
import Dropdown from "../../components/Login/Dropdown";
import Input from "../../components/Login/Input";
import TextButton from "../../components/Login/TextButton";
import useInput from "../../hooks/useInput";
import classes from "./Login.module.css";

const Register = () => {
  const {
    value: enteredEmail,
    shouldDisplayError: emailDisplayError,
    isValid: emailIsValid,
    valueChangeHandler: emailChangeHandler,
    onBlurHandler: emailBlurHandler,
    reset: resetEmail,
  } = useInput((value) => value.includes("@"));

  const {
    value: enteredPassword,
    shouldDisplayError: passwordDisplayError,
    isValid: passwordIsValid,
    valueChangeHandler: passwordChangeHandler,
    onBlurHandler: passwordBlurHandler,
    reset: resetPassword,
  } = useInput((value) => value.trim() !== "");

  const {
    value: enteredUsername,
    shouldDisplayError: usernameDisplayError,
    isValid: usernameIsValid,
    valueChangeHandler: usernameChangeHandler,
    onBlurHandler: usernameBlurHandler,
    reset: resetUsername,
  } = useInput((value) => value.trim() !== "");

  let emailErrorText = "";

  const onSubmitHandler = async (event) => {
    event.preventDefault();

    const data = {
      email: enteredEmail,
      password: enteredPassword,
      username: enteredUsername,
    };

    try {
      const response = await fetch("/auth/register", {
        method: "POST",
        body: JSON.stringify(data),
        headers: { "Content-Type": "application/json" },
      });

      // let newData = await response.json();
      // console.log(newData);
    } catch (err) {
      console.log(err);
    }

    if (passwordDisplayError || emailDisplayError) {
      // console.log("HERE")
      // displayError = true;
    }

    if (!passwordIsValid || !emailIsValid) {
      return;
    }
  };

  return (
    <div className={classes["wrapper"]}>
      <form className={classes["form"]} onSubmit={onSubmitHandler}>
        <div className={classes["header"]}>
          <h1 className={classes["heading"]}>Create an account </h1>
        </div>
        <div className={classes["block"]}>
          <Input
            name="email"
            label="email"
            type="text"
            onChange={emailChangeHandler}
            onBlur={emailBlurHandler}
            value={enteredEmail}
          ></Input>
          <Input
            name="username"
            label="username"
            type="text"
            onChange={usernameChangeHandler}
            onBlur={usernameBlurHandler}
            value={enteredUsername}
          ></Input>
          <Input
            name="password"
            label="password"
            type="password"
            onChange={passwordChangeHandler}
            onBlur={passwordBlurHandler}
            value={enteredPassword}
          ></Input>
          <fieldset>
            <Dropdown></Dropdown>
            <Dropdown></Dropdown>
            <Dropdown></Dropdown>
          </fieldset>
          <Button type="submit">Continue</Button>
          <div>
            <TextButton>Already have an account?</TextButton>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Register;
